<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>@yield('title','Wallet') - LedgerFlow</title><style>:root{--ink:#172033;--muted:#667085;--line:#e5e7eb;--bg:#f4f7fb;--brand:#165dff;--good:#067647;--bad:#b42318}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--ink);font:14px/1.5 system-ui}.bar{height:68px;background:#fff;border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:space-between;padding:0 max(24px,calc((100vw - 1120px)/2))}.brand{font-size:20px;font-weight:800}.nav{display:flex;gap:18px;align-items:center}.nav a{text-decoration:none;color:inherit}.main{max-width:1120px;margin:30px auto;padding:0 20px}h1{font-size:27px}.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}.card{background:#fff;border:1px solid var(--line);border-radius:12px;padding:18px}.wallet{border-top:4px solid var(--brand)}.amount{font-size:26px;font-weight:750;font-variant-numeric:tabular-nums}.muted{color:var(--muted)}.button{display:inline-flex;align-items:center;justify-content:center;height:40px;border:0;border-radius:8px;padding:0 14px;background:var(--brand);color:#fff;text-decoration:none;font-weight:650;cursor:pointer}.button.secondary{background:#344054}.button.danger{background:#b42318}.actions{display:flex;gap:9px;flex-wrap:wrap}.table{width:100%;border-collapse:collapse;background:#fff;border-radius:12px;overflow:hidden}.table th,.table td{padding:12px;border-bottom:1px solid var(--line);text-align:left}.badge{padding:3px 8px;border-radius:99px;background:#eef2f6}.completed,.active{background:#ecfdf3;color:var(--good)}.failed,.frozen{background:#fef3f2;color:var(--bad)}.alert{padding:12px;border-radius:8px;background:#ecfdf3;color:var(--good);margin-bottom:14px}.alert.error{background:#fef3f2;color:var(--bad)}input,select,textarea{width:100%;height:42px;border:1px solid #d0d5dd;border-radius:8px;padding:9px 11px}label{display:block;